codingChallenges.description:
The following code creates functions that should return 0, 1, 2, 3, 4 but all return 4. Fix it using the default parameter technique.<br><pre><code>funcs = []
for i in range(5):
    def f():
        return i
    funcs.append(f)
print([fn() for fn in funcs])  # [4, 4, 4, 4, 4]</code></pre>

codingChallenges.solution:
funcs = []
for i in range(5):
    def f(i=i):
        return i
    funcs.append(f)
print([fn() for fn in funcs])

def make_rate_limiter(max_calls):
    calls = 0
    def check():
        nonlocal calls
        calls += 1
        if calls > max_calls:
            return "Rate limit exceeded"
        return "OK"
    return check

limiter = make_rate_limiter(3)
for i in range(1, 6):
    print(f"Call {i}: {limiter()}")

def memoize(func):
    cache = {}
    def wrapper(n):
        if n not in cache:
            print(f"Computing {func.__name__}({n})...")
            cache[n] = func(n)
        return cache[n]
    return wrapper

def factorial(n):
    if n <= 1:
        return 1
    return n * factorial(n - 1)

factorial = memoize(factorial)
print(factorial(5))
print(factorial(5))
print(factorial(3))
